import React, { useState, useEffect, useMemo } from 'react';
import axios from 'axios';

const ProjectDashboard = ({ theme = 'dark' }) => {
  const [data, setData] = useState([]);
  const [error, setError] = useState(null);

  const fetchData = async () => {
    try {
      const response = await axios.get('/api/v2/projects');
      setData(response.data);
    } catch (err) {
      setError('Failed to load project data');
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const listItems = useMemo(() => {
    return data.map(item => (
      <div className="card" key={item.id}>
        <h3>{item.name}</h3>
        <p>{item.description || 'No description available'}</p>
      </div>
    ));
  }, [data]);

  if (error) return <div className="error">{error}</div>;

  return (
    <main style={{ padding: '20px', backgroundColor: theme === 'dark' ? '#111' : '#fff' }}>
      <header>
        <h2 style={{ color: '#61afef' }}>Project Overview</h2>
        <button onClick={fetchData}>Refresh Data</button>
      </header>
      <section className="grid-layout">
        {data.length > 0 ? listItems : <p>No projects found.</p>}
      </section>
    </main>
  );
};

export default ProjectDashboard;
